import CryptoJS from 'crypto-js';
import { ENCRYPTION_KEY } from '../config/keys';

/**
 * Encrypts data using AES encryption.
 * The data is first stringified (if it's an object) and then encrypted.
 *
 * @param {any} data The data to encrypt (can be object, string, number, etc.)
 * @returns {string | null} The encrypted string, or null if input is null/undefined.
 */
const encryptData = (data) => {
  if (data === null || typeof data === 'undefined') {
    return null;
  }
  const stringifiedData = JSON.stringify(data);
  const encrypted = CryptoJS.AES.encrypt(stringifiedData, ENCRYPTION_KEY).toString();
  return encrypted;
};

/**
 * Decrypts data using AES encryption.
 * The decrypted string is then parsed back to its original type (if it was an object).
 *
 * @param {string | null} ciphertext The encrypted string to decrypt.
 * @returns {any | null} The decrypted data, or null if decryption fails or input is null/undefined.
 */
const decryptData = (ciphertext) => {
  if (!ciphertext) {
    return null;
  }
  try {
    const decryptedBytes = CryptoJS.AES.decrypt(ciphertext, ENCRYPTION_KEY);
    if (decryptedBytes.sigBytes <= 0) { // Check if decryption yielded any bytes
        console.warn('Decryption resulted in empty bytes, likely wrong key or corrupted data.');
        return null;
    }
    const decryptedString = decryptedBytes.toString(CryptoJS.enc.Utf8);
    return JSON.parse(decryptedString);
  } catch (error) {
    console.error('Decryption failed, returning null. Error:', error);
    // This could happen if the key is wrong or the data is corrupted/not encrypted.
    return null;
  }
};

export { encryptData, decryptData };

